          { id: 2, user: "FocusedMind", text: "Pomodoro changed my study habits completely!", time: "10:15 AM" }
        ]
      },
      {
        id: 2,
        user: "ExamSurvivor",
        text: "Anyone have tips for dealing with test anxiety?",
        time: "10:45 AM",
        reactions: { like: 8, support: 5 },
        replies: []
